import time
import plotly.graph_objects as go
from plotly.subplots import make_subplots

# 1. Arrays for Data Collection
depths = [2,4,6,8]
nodes_std, nodes_ab = [], []
times_std, times_ab = [], []

initial_state = (2.5, 500, 78, 0.5)

print("Starting Depth Scaling Analysis. Collecting data...")

# 2. Loop
for d in depths:
    print(f"  -> Testing Depth {d}...")

    # Reset counters for this specific depth
    eval_count_std = 0
    eval_count_ab = 0

    # Benchmark Standard Minimax
    t0_std = time.time()
    minimax_standard(d, True, initial_state)
    t1_std = time.time()

    nodes_std.append(eval_count_std)
    times_std.append(t1_std - t0_std)

    # Benchmark Alpha-Beta Pruning
    t0_ab = time.time()
    minimax_alpha_beta(d, True, initial_state, float('-inf'), float('inf'))
    t1_ab = time.time()

    nodes_ab.append(eval_count_ab)
    times_ab.append(t1_ab - t0_ab)

print("Data collection complete! Generating scaling graphs...")

# 3.Plotly Visualizations
fig = make_subplots(
    rows=1, cols=2,
    subplot_titles=('<b>Nodes Evaluated vs. Depth</b>', '<b>Execution Time vs. Depth</b>'),
    horizontal_spacing=0.1
)

# Colors
color_std = '#EF553B' # Coral
color_ab = '#636EFA'  # Blue

# Subplot 1: Nodes vs Depth
fig.add_trace(go.Scatter(x=depths, y=nodes_std, mode='lines+markers', name='Standard Minimax',
                         line=dict(color=color_std, width=3), marker=dict(size=8)), row=1, col=1)
fig.add_trace(go.Scatter(x=depths, y=nodes_ab, mode='lines+markers', name='Alpha-Beta',
                         line=dict(color=color_ab, width=3), marker=dict(size=8)), row=1, col=1)

# Subplot 2: Time vs Depth
fig.add_trace(go.Scatter(x=depths, y=times_std, mode='lines+markers', showlegend=False,
                         line=dict(color=color_std, width=3), marker=dict(size=8)), row=1, col=2)
fig.add_trace(go.Scatter(x=depths, y=times_ab, mode='lines+markers', showlegend=False,
                         line=dict(color=color_ab, width=3), marker=dict(size=8)), row=1, col=2)

# Formatting
fig.update_layout(
    title="<b>Complexity Scaling: Standard Minimax vs. Alpha-Beta</b>",
    title_x=0.5,
    title_font_size=20,
    template="plotly_white",
    height=550,

    # THE FIX: Centered neatly at the bottom
    legend=dict(
        orientation="h",   # Horizontal layout
        yanchor="top",
        y=-0.25,           # Pushed safely below the x-axis titles
        xanchor="center",
        x=0.5              # Centered perfectly
    ),


    margin=dict(t=80, b=120),

    font=dict(family="Arial", size=13)
)

fig.update_xaxes(title_text="Search Depth", tickvals=depths)
fig.update_yaxes(title_text="Number of Nodes", row=1, col=1)
fig.update_yaxes(title_text="Execution Time (Seconds)", row=1, col=2)

fig.show()